--
-- Name: auth_api_key; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.auth_api_key (
    id bigint NOT NULL,
    user_id bigint NOT NULL,
    key_name character varying(64) NOT NULL,
    key_prefix character varying(8) NOT NULL,
    key_hash character varying(128) NOT NULL,
    usage_scope character varying(32) DEFAULT '全部接口'::character varying NOT NULL,
    expires_at timestamp without time zone,
    last_used_at timestamp without time zone,
    status character varying(16) NOT NULL,
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    allowed_resources character varying(2000),
    allowed_actions character varying(512),
    CONSTRAINT chk_api_key_status CHECK (((status)::text = ANY ((ARRAY['有效'::character varying, '已禁用'::character varying])::text[])))
);


--
-- Name: auth_refresh_token; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.auth_refresh_token (
    id bigint NOT NULL,
    user_id bigint NOT NULL,
    token_id character varying(36) NOT NULL,
    token_hash character varying(128) NOT NULL,
    expires_at timestamp without time zone NOT NULL,
    revoked_at timestamp without time zone,
    login_ip character varying(64),
    device_info character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    revoke_reason character varying(32),
    CONSTRAINT chk_refresh_token_revoke_reason CHECK (((revoke_reason IS NULL) OR ((revoke_reason)::text = ANY ((ARRAY['MANUAL'::character varying, 'CONCURRENT_LIMIT'::character varying, 'EXPIRED'::character varying])::text[]))))
);


--
-- Name: COLUMN auth_refresh_token.revoke_reason; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.auth_refresh_token.revoke_reason IS '撤销原因: MANUAL/CONCURRENT_LIMIT/EXPIRED';


